// =========================
// ABBEY GENERATOR
// Sandbox Generator
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function tableRoll(value, table) {
    return table.find(row => value >= row.min && value <= row.max);
}

function uniqueRolls(count, sides) {
    const results = [];
    while (results.length < count) {
        const r = roll(sides);
        if (!results.includes(r)) results.push(r);
    }
    return results;
}

// -------------------------
// TABLES
// -------------------------

const saints = [
    "Adélie", "Agath", "Alexia", "Aubreda", "Bardolphus",
"Barthélemy", "Beatrix", "Bérengérius", "Bernardus", "Cecilia",
"Cédany", "Émelote", "Gaufridus", "Geffrey", "Géroldin",
"Guillotin", "Jaclyn", "Jacomus", "Madeleine", "Marion",
"Mariorie", "Martin", "Mary", "Melchior", "Paul",
"Pétasse", "Peter", "Remy", "Thomasse", "Victor"
];

const abbeyNameTable = [
    "Blessed-Land",
"Clear-Water",
"Fruitful-Garden",
"Good-...",
"Our-Lady-of-...",
"Peaceful-Soul",
"Sacred-Heart",
"Saint-...",
"Saint-...",
"Saint-..."
];

const goodSubtable = ["Help", "Hope", "Relief"];
const ladySubtable = ["Chastity", "Mercy", "the Poor"];

const sizeTable = [
    { min: 1, max: 5, result: "Small" },
{ min: 6, max: 6, result: "Major" }
];

const coreLocations = [
    "Abbot’s room",
"Cellars",
"Cemetery",
"Church",
"Cloisters and garden",
"Infirmary",
"Kitchen and refectory",
"Monks cells",
"Necessarium / latrines",
"Servants, laborers, and tradesmen quarters",
"Storehouses"
];

const gardens = [
    "Flower garden",
"Fountain",
"Kitchen garden",
"Physic garden / medicine garden"
];

const infirmary = [
    "Bloodletting & purging room",
"Drugstore",
"Physician’s residence",
"Room for critical patients"
];

const religiousBuildings = [
    "Chapter house / meeting room",
"Parlour",
"School",
"Scriptorium and library"
];

const otherLocations = [
    "Abbot’s gateway",
"Barns and stables",
"Guest rooms",
"Vestarium / clothing storage",
"Washhouse",
"Watchtower"
];

const farming = [
    "Barley / beer",
"Chickens / meat and eggs",
"Cotton",
"Cows / meat, milk, and cheese",
"Goats / meat, milk, and cheese",
"Grapes / wine",
"Hops / beer",
"Orchard / fruits and preserves",
"Pigs / meat",
"Sheep / meat and wool",
"Vegetables",
"Wheat / flour and bread"
];

const workshops = [
    "Candle makers",
"Cutlers",
"Potters",
"Shoemakers",
"Smiths",
"Tanners"
];

const otherActivities = [
    "Bee keeping",
"Bookshop",
"Catering",
"Copy & translation",
"Exorcism",
"Guided tour"
];

const fameTable = [
    { min: 1, max: 1, result: "Age" },
{ min: 2, max: 2, result: "Architecture" },
{ min: 3, max: 3, result: "Cattle baptism" },
{ min: 4, max: 4, result: "Curative hot springs" },
{ min: 5, max: 5, result: "Domain and landscapes" },
{ min: 6, max: 6, result: "Grave of well known bishop" },
{ min: 7, max: 7, result: "Key religious celebration" },
{ min: 8, max: 8, result: "Meals served to travelers" },
{ min: 9, max: 9, result: "Pilgrimage" },
{ min: 10, max: 10, result: "Power" },
{ min: 11, max: 11, result: "Quality of products" },
{ min: 12, max: 20, result: "Religious artifact" }
];

const religiousArtifacts = [
    "Ancient parchment",
"Art piece",
"Crown",
"Holy sword",
"Precious book",
"Relic"
];

const relicTypes = [
    "Arm",
"Blood",
"Bones / vertebra or phalanx",
"Eye",
"Flesh",
"Head",
"Heart",
"Item that killed the saint",
"Leg",
"Piece of clothing",
"Prayer book",
"Religious symbol",
"Ring",
"Sandals",
"Scalp",
"Shroud",
"Skin",
"Tongue",
"Tooth",
"Walking stick"
];

const spellLevelTable = [
    { min: 1, max: 8, result: "Level 1" },
{ min: 9, max: 14, result: "Level 2" },
{ min: 15, max: 17, result: "Level 3" },
{ min: 18, max: 19, result: "Level 4" },
{ min: 20, max: 20, result: "Level 5" }
];

const eventTimingTable = [
    { min: 1, max: 1, result: "Ended earlier" },
{ min: 2, max: 4, result: "Is happening now" },
{ min: 5, max: 6, result: "Will take place in the future" }
];

const abbeyEvents = [
    "Broken device",
"Cowls shrunken/dyed in red",
"Demonic corruption",
"Disappearance of the abbot",
"Drought/Flood",
"Festival/Fair",
"Fire",
"Looting",
"Moles/Rats infestation",
"Plague",
"Scandal",
"Visit of a notable person"
];

const historyTable = [
    "Abandoned then used again",
"Changed confession",
"Claimed its autonomy",
"Destroyed then rebuilt",
"Founded 2d10 × 10 years ago",
"Has seen better days",
"Only one original building remains",
"Sponsored by a rich patron",
"Started as a knight hermitage",
"Used to be a boarding school",
"Was relocated",
"Was under a spell"
];

// -------------------------
// NAME
// -------------------------

let nameRoll = roll(10);
let namePattern = abbeyNameTable[nameRoll - 1];

let abbeyName = "";
let nameExtraRoll = null;
let saintRoll = null;
let saint = null;

if (namePattern === "Good-...") {
    nameExtraRoll = roll(3);
    abbeyName = `Abbey of Good-${goodSubtable[nameExtraRoll - 1]}`;
} else if (namePattern === "Our-Lady-of-...") {
    nameExtraRoll = roll(3);
    abbeyName = `Abbey of Our-Lady-of-${ladySubtable[nameExtraRoll - 1]}`;
} else if (namePattern === "Saint-...") {
    saintRoll = roll(30);
    saint = saints[saintRoll - 1];
    abbeyName = `Abbey of Saint-${saint}`;
} else {
    abbeyName = `Abbey of ${namePattern}`;
}

// -------------------------
// SIZE / MONKS / ABBOT
// -------------------------

let sizeRoll = roll(6);
let abbeySize = tableRoll(sizeRoll, sizeTable).result;

let monkRoll = null;
let monks = 0;

if (abbeySize === "Small") {
    monkRoll = roll(4);
    monks = monkRoll * 10 + 20;
} else {
    monkRoll = roll(24);
    monks = monkRoll * 10 + 90;
}

let abbotLevel = 9;

if (abbeySize === "Small" && monks >= 50) {
    abbotLevel += 1;
}

if (abbeySize === "Major") {
    abbotLevel += Math.floor(monks / 100);
}

// -------------------------
// ADDITIONAL LOCATIONS
// -------------------------

let gardenRoll = roll(4);
let garden = gardens[gardenRoll - 1];

let infirmaryRoll = roll(4);
let infirmaryLocation = infirmary[infirmaryRoll - 1];

let religiousRoll = roll(4);
let religiousLocation = religiousBuildings[religiousRoll - 1];

let otherRoll = roll(6);
let otherLocation = otherLocations[otherRoll - 1];

// -------------------------
// ACTIVITIES
// -------------------------

let farmingRolls = uniqueRolls(2, 12);
let farmingResults = farmingRolls.map(r => ({
    roll: r,
    result: farming[r - 1]
}));

let workshopRoll = roll(6);
let workshop = workshops[workshopRoll - 1];

let otherActivityRoll = roll(6);
let otherActivity = otherActivities[otherActivityRoll - 1];

// -------------------------
// FAME / ARTIFACT
// -------------------------

let fameRoll = null;
let fame = "None";
let artifactRoll = null;
let artifact = null;

let relicRoll = null;
let relic = null;
let relicSaintRoll = null;
let relicSaint = null;
let spellLevelRoll = null;
let spellLevel = null;

if (abbeySize === "Major") {
    fameRoll = roll(20);
    fame = tableRoll(fameRoll, fameTable).result;

    if (fame === "Religious artifact") {
        artifactRoll = roll(6);
        artifact = religiousArtifacts[artifactRoll - 1];

        if (artifact === "Relic") {
            relicRoll = roll(20);
            relic = relicTypes[relicRoll - 1];

            relicSaintRoll = roll(30);
            relicSaint = saints[relicSaintRoll - 1];

            spellLevelRoll = roll(20);
            spellLevel = tableRoll(spellLevelRoll, spellLevelTable).result;
        }
    }
}

// -------------------------
// EVENT
// -------------------------

let eventCheckRoll = roll(6);
let hasEvent = eventCheckRoll === 1;

let eventTimingRoll = null;
let eventTiming = "None";
let eventRoll = null;
let event = "None";

if (hasEvent) {
    eventTimingRoll = roll(6);
    eventTiming = tableRoll(eventTimingRoll, eventTimingTable).result;

    eventRoll = roll(12);
    event = abbeyEvents[eventRoll - 1];
}

// -------------------------
// HISTORY
// -------------------------

let historyRoll = roll(12);
let history = historyTable[historyRoll - 1];

let foundedRoll1 = null;
let foundedRoll2 = null;
let foundedYears = null;

if (history === "Founded 2d10 × 10 years ago") {
    foundedRoll1 = roll(10);
    foundedRoll2 = roll(10);
    foundedYears = (foundedRoll1 + foundedRoll2) * 10;
    history = `Founded ${foundedYears} years ago`;
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Abbey Generator</h2>

<h3>Name</h3>
<p><b>Name Roll:</b> d10 = ${nameRoll}</p>
<p><b>Name Pattern:</b> ${namePattern}</p>
${nameExtraRoll ? `<p><b>Name Subtable Roll:</b> d3 = ${nameExtraRoll}</p>` : ""}
${saintRoll ? `<p><b>Saint Roll:</b> d30 = ${saintRoll} → ${saint}</p>` : ""}
<p><b>Abbey Name:</b> ${abbeyName}</p>

<hr>

<h3>Size and Inhabitants</h3>
<p><b>Size Roll:</b> d6 = ${sizeRoll}</p>
<p><b>Size:</b> ${abbeySize}</p>
<p><b>Monks/Nuns Roll:</b> ${abbeySize === "Small" ? `1d4 × 10 + 20 = ${monkRoll} × 10 + 20` : `1d24 × 10 + 90 = ${monkRoll} × 10 + 90`}</p>
<p><b>Monks/Nuns:</b> ${monks}</p>
<p><b>Abbot/Abbess Level:</b> ${abbotLevel}</p>

<hr>

<h3>Structure and Land</h3>
<p>The abbey is protected by a <b>stone wall with a large gate</b>.</p>
<p>Outside the walls are <b>fields</b> and farming buildings such as barns, mills, and related work areas.</p>
<p>The walled area is usually about <b>3–4 acres</b>.</p>

<hr>

<h3>Core Locations</h3>
<ul>
${coreLocations.map(l => `<li>${l}</li>`).join("")}
</ul>

<hr>

<h3>Additional Locations</h3>
<p><b>Garden Roll:</b> d4 = ${gardenRoll} → <b>${garden}</b></p>
<p><b>Infirmary Roll:</b> d4 = ${infirmaryRoll} → <b>${infirmaryLocation}</b></p>
<p><b>Religious Building Roll:</b> d4 = ${religiousRoll} → <b>${religiousLocation}</b></p>
<p><b>Other Location Roll:</b> d6 = ${otherRoll} → <b>${otherLocation}</b></p>

<hr>

<h3>Activities</h3>
<p><b>Farming Rolls:</b> Roll d12 twice, rerolling duplicates.</p>
<ul>
${farmingResults.map(f => `<li>d12 = ${f.roll} → ${f.result}</li>`).join("")}
</ul>
<p><b>Workshop Roll:</b> d6 = ${workshopRoll} → <b>${workshop}</b></p>
<p><b>Other Activity Roll:</b> d6 = ${otherActivityRoll} → <b>${otherActivity}</b></p>

<hr>

<h3>Fame</h3>
${abbeySize === "Major" ? `
    <p><b>Fame Roll:</b> d20 = ${fameRoll}</p>
    <p><b>Famous For:</b> ${fame}</p>
    ${artifact ? `<p><b>Religious Artifact Roll:</b> d6 = ${artifactRoll}</p><p><b>Artifact:</b> ${artifact}</p>` : ""}
    ${relic ? `
        <p><b>Relic Type Roll:</b> d20 = ${relicRoll}</p>
        <p><b>Relic:</b> ${relic} of Saint-${relicSaint}</p>
        <p><b>Relic Saint Roll:</b> d30 = ${relicSaintRoll}</p>
        <p><b>Priest Spell Level Roll:</b> d20 = ${spellLevelRoll}</p>
        <p><b>Spell Level Held in Relic:</b> ${spellLevel}</p>
        <p><i>A relic can cast its spell once per week. If used twice in the same week, it is destroyed after casting.</i></p>
        ` : ""}
        ` : `
        <p><b>Fame:</b> None rolled. Only major abbeys use the fame table.</p>
        `}

        <hr>

        <h3>Event</h3>
        <p><b>Event Check:</b> d6 = ${eventCheckRoll}</p>
        <p><b>Has Event:</b> ${hasEvent ? "Yes" : "No"}</p>
        ${hasEvent ? `
            <p><b>Event Timing Roll:</b> d6 = ${eventTimingRoll}</p>
            <p><b>Timing:</b> ${eventTiming}</p>
            <p><b>Event Roll:</b> d12 = ${eventRoll}</p>
            <p><b>Event:</b> ${event}</p>
            ` : `<p><b>Event:</b> None</p>`}

            <hr>

            <h3>History</h3>
            <p><b>History Roll:</b> d12 = ${historyRoll}</p>
            ${foundedYears ? `<p><b>Founded Roll:</b> 2d10 × 10 = (${foundedRoll1} + ${foundedRoll2}) × 10</p>` : ""}
            <p><b>History:</b> ${history}</p>

            <hr>

            <h3>Quick Summary</h3>
            <p>
            <b>${abbeyName}</b> is a <b>${abbeySize.toLowerCase()}</b> abbey with
            <b>${monks}</b> monks/nuns, led by a level <b>${abbotLevel}</b> abbot/abbess.
            It has a <b>${garden.toLowerCase()}</b>, <b>${infirmaryLocation.toLowerCase()}</b>,
            <b>${religiousLocation.toLowerCase()}</b>, and <b>${otherLocation.toLowerCase()}</b>.
            Its farming includes <b>${farmingResults.map(f => f.result.toLowerCase()).join(", ")}</b>.
            It also has <b>${workshop.toLowerCase()}</b> and offers <b>${otherActivity.toLowerCase()}</b>.
            ${abbeySize === "Major" ? `It is famous for <b>${fame.toLowerCase()}</b>.` : ""}
            ${relic ? ` It keeps the <b>${relic.toLowerCase()} of Saint-${relicSaint}</b>, holding a <b>${spellLevel}</b> priest spell.` : ""}
            ${hasEvent ? ` Event: <b>${event}</b> — ${eventTiming.toLowerCase()}.` : ""}
            History: <b>${history.toLowerCase()}</b>.
            </p>
            `;
            if (globalThis.currentHexFaction) {
                output += `
                <hr>

                <h3>Faction</h3>

                <p><b>Controlling Faction:</b></p>
                <p>${globalThis.currentHexFaction}</p>
                `;
            }

            ChatMessage.create({
                speaker: ChatMessage.getSpeaker(),
                               content: output
            });
